// Simple tab redirection to tutorial page
async function redirectToTutorial(tabId) {
    if (!tabId)
        return;
    try {
        await chrome.tabs.update(tabId, { url: 'https://browser.windsurf.com' });
    }
    catch (error) {
        // Silently ignore redirect failures
    }
}
// Check if URL should be redirected
function shouldRedirect(url) {
    return (!url ||
        url === 'about:blank' ||
        url === 'chrome://newtab/' ||
        url === 'chrome://new-tab-page/' ||
        url.startsWith('edge://newtab') ||
        url.startsWith('opera://startpage'));
}
// Identify the initial startup tab (do not redirect it)
function recordInitialStartupTab() {
    chrome.tabs.query({}, (tabs) => {
        // Only consider if there's exactly one tab (typical browser startup scenario)
        if (tabs.length === 1 && tabs[0]) {
            const url = tabs[0].pendingUrl || tabs[0].url || '';
            if (tabs[0].id != null && shouldRedirect(url)) {
                initialStartupTabId = tabs[0].id;
                initialStartupSkipConsumed = false;
            }
        }
    });
}
// Run on any service worker startup (covers re-enable after disable)
recordInitialStartupTab();
// Run when browser starts (additional coverage)
chrome.runtime.onStartup.addListener(() => {
    recordInitialStartupTab();
});
// Run on extension install (covers first-time install)
chrome.runtime.onInstalled.addListener((details) => {
    if (details.reason === 'install') {
        recordInitialStartupTab();
    }
});
// Redirect ALL new tabs to browser.windsurf.com
chrome.tabs.onCreated.addListener((tab) => {
    // New tabs typically start with chrome://new-tab-page/ or about:blank
    const candidateUrl = tab.pendingUrl || tab.url || '';
    if (tab.id != null && shouldRedirect(candidateUrl)) {
        // Skip redirect once for the very first startup tab
        if (initialStartupTabId === tab.id && !initialStartupSkipConsumed) {
            initialStartupSkipConsumed = true;
            return;
        }
        redirectToTutorial(tab.id);
    }
});
// Also catch tabs that navigate to new tab page
chrome.tabs.onUpdated.addListener((tabId, changeInfo) => {
    if (changeInfo.url && shouldRedirect(changeInfo.url)) {
        // Skip redirect once for the very first startup tab
        if (initialStartupTabId === tabId && !initialStartupSkipConsumed) {
            initialStartupSkipConsumed = true;
            return;
        }
        redirectToTutorial(tabId);
    }
});
