// SERVICE WORKER WAKE-UP FOR PLAYWRIGHT VISIBILITY
// =============================================================================
/**
 * Simple wake-up to ensure service worker is active and visible to Playwright.
 * Manifest V3 service workers are lazy - they need to be active to show up in
 * context.serviceWorkers(). This ensures Playwright can find the extension.
 */
function wakeUpServiceWorker() {
    // Send a self-message to activate the service worker
    chrome.runtime.sendMessage(chrome.runtime.id, { type: 'PING' }).catch(() => {
        // Expected - self-messaging often produces this error, but it activates the worker
        // This is normal and expected - silently ignore
    });
    // Keep active for 60 seconds after startup to ensure Playwright has time to detect
    const keepAliveInterval = setInterval(() => {
        // Keep-alive ping
    }, 10000); // Every 10 seconds
    setTimeout(() => {
        clearInterval(keepAliveInterval);
    }, 60000); // Stop after 60 seconds
}
// Wake up the service worker immediately when this script loads
// This makes the worker visible to Playwright's serviceWorkers() detection
wakeUpServiceWorker();
// Also wake up on extension install/update
chrome.runtime.onInstalled.addListener(() => {
    wakeUpServiceWorker();
});
